const items = $input.all();

//
// ## VIRALITY THRESHOLD
// Raise this if too many videos are marked VIRAL.
// Lower this if too few videos are marked VIRAL.
//
const VIRALITY_THRESHOLD = 50;

//
// ## MINIMUM AGE PROTECTION
// Prevents brand-new videos from getting absurdly high scores
// just because they were posted a few minutes ago.
// Example: 15 means anything newer than 15 minutes is treated as 15 minutes old.
//
const MINIMUM_AGE_MINUTES = 15;

//
// ## COMMENT WEIGHT
// Comments usually indicate stronger engagement than likes.
// Example: 4 means 1 comment counts like 4 likes.
//
const COMMENT_WEIGHT = 3;

//
// ## SCORE WEIGHTS
// These control how much each factor contributes to the final score.
// Increase a weight to make that factor matter more.
//
const VIEW_VELOCITY_WEIGHT = 20;
const ENGAGEMENT_VELOCITY_WEIGHT = 15;
const ENGAGEMENT_RATE_WEIGHT = 1.5;
const SUBSCRIBER_OUTPERFORMANCE_WEIGHT = 20;

//
// ## CAPS
// Caps prevent one extreme metric from dominating the whole score.
//
const MAX_ENGAGEMENT_RATE_PERCENT = 20;
const MAX_SUBSCRIBER_OUTPERFORMANCE = 5;

//
// ## DEFAULT FALLBACKS
// Used when a field is missing or unreadable.
//
const DEFAULT_MINUTES_AGO = 1440;
const DEFAULT_SUBSCRIBERS = 1;

function parseNumber(value, fallback = 0) {
  if (value === null || value === undefined || value === '') return fallback;

  if (typeof value === 'number') return value;

  const raw = String(value)
    .trim()
    .replace(/,/g, '')
    .replace(/\s+/g, '');

  const match = raw.match(/^([\d.]+)([KMB])?/i);
  if (!match) return fallback;

  const num = parseFloat(match[1]);
  const suffix = (match[2] || '').toUpperCase();

  const multiplier =
    suffix === 'K' ? 1e3 :
    suffix === 'M' ? 1e6 :
    suffix === 'B' ? 1e9 :
    1;

  return num * multiplier;
}

function parseMinutesAgo(value) {
  if (value === null || value === undefined || value === '') return null;

  if (typeof value === 'number') return value;

  const raw = String(value).trim();

  // Handles plain numbers like "123" or "123.5"
  if (/^\d+(\.\d+)?$/.test(raw)) {
    return parseFloat(raw);
  }

  // Handles strings like "123 minutes ago", "2 hours ago", "4 days ago"
  const relativeMatch = raw.match(/^(\d+)\s+(second|minute|hour|day|week|month|year)s?\s+ago$/i);

  if (relativeMatch) {
    const amount = parseInt(relativeMatch[1], 10);
    const unit = relativeMatch[2].toLowerCase();

    const multipliers = {
      second: 1 / 60,
      minute: 1,
      hour: 60,
      day: 1440,
      week: 10080,
      month: 43200,
      year: 525600
    };

    return amount * multipliers[unit];
  }

  return null;
}

return items.map(item => {
  const views = parseNumber(item.json['VIDEO VIEWS']);
  const likes = parseNumber(item.json['VIDEO LIKES']);
  const comments = parseNumber(item.json['VIDEO COMMENTS']);
  const subscribers = parseNumber(item.json['SUBSCRIBER COUNT'], DEFAULT_SUBSCRIBERS);

  const minutesAgo =
    parseMinutesAgo(item.json['MINUTES AGO']) ??
    DEFAULT_MINUTES_AGO;

  const protectedMinutesAgo = Math.max(minutesAgo, MINIMUM_AGE_MINUTES);
  const hoursSincePublish = protectedMinutesAgo / 60;

  //
  // ## RAW VELOCITY METRICS
  //
  const viewsPerHour = views / hoursSincePublish;
  const likesPerHour = likes / hoursSincePublish;
  const commentsPerHour = comments / hoursSincePublish;

  //
  // ## ENGAGEMENT METRICS
  //
  const weightedEngagements = likes + (comments * COMMENT_WEIGHT);
  const weightedEngagementsPerHour = weightedEngagements / hoursSincePublish;

  const engagementRate = weightedEngagements / Math.max(views, 1);
  const engagementRatePercent = engagementRate * 100;

  //
  // ## CHANNEL OUTPERFORMANCE
  // Measures how much the video is outperforming the channel size.
  // Example: 5,000 views from a 1,000-sub channel = 5x subscriber outperformance.
  //
  const subscriberOutperformance = views / Math.max(subscribers, 1);

  //
  // ## FINAL SCORE
  // log10 prevents massive channels from completely dominating.
  //
  const velocityScore =
    (Math.log10(1 + viewsPerHour) * VIEW_VELOCITY_WEIGHT) +
    (Math.log10(1 + weightedEngagementsPerHour) * ENGAGEMENT_VELOCITY_WEIGHT) +
    (Math.min(engagementRatePercent, MAX_ENGAGEMENT_RATE_PERCENT) * ENGAGEMENT_RATE_WEIGHT) +
    (Math.min(subscriberOutperformance, MAX_SUBSCRIBER_OUTPERFORMANCE) * SUBSCRIBER_OUTPERFORMANCE_WEIGHT);

  const roundedScore = Math.round(velocityScore * 100) / 100;

  return {
    json: {
      ...item.json,

      minutes_ago_numeric: Math.round(minutesAgo),
      protected_minutes_ago: Math.round(protectedMinutesAgo),
      hours_since_publish: Math.round(hoursSincePublish * 100) / 100,

      views_per_hour: Math.round(viewsPerHour * 100) / 100,
      likes_per_hour: Math.round(likesPerHour * 100) / 100,
      comments_per_hour: Math.round(commentsPerHour * 100) / 100,

      weighted_engagements: weightedEngagements,
      weighted_engagements_per_hour: Math.round(weightedEngagementsPerHour * 100) / 100,

      engagement_rate_percent: Math.round(engagementRatePercent * 100) / 100,
      subscriber_outperformance: Math.round(subscriberOutperformance * 100) / 100,

      velocity_score: roundedScore,
      is_viral: roundedScore >= VIRALITY_THRESHOLD ? 'VIRAL' : 'NOT VIRAL',

      velocity_summary:
        `Score ${roundedScore} | ` +
        `${Math.round(viewsPerHour)} views/hr | ` +
        `${Math.round(weightedEngagementsPerHour)} weighted engagements/hr | ` +
        `${Math.round(engagementRatePercent * 100) / 100}% engagement | ` +
        `${Math.round(subscriberOutperformance * 100) / 100}x subs`
    }
  };
});

const video = $('Google Sheets - Get SELECTED Video').first().json;
