const sources = $input.first().json.output.sources || [];

const seen = new Set();

const deduped = sources.filter(source => {
  if (!source.url) return false;

  const key = source.url
    .replace(/^https?:\/\//, '')
    .replace(/\/+$/, '')
    .replace(/\?.*$/, '')
    .toLowerCase();

  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const tier1Domains = [
  'nature.com',
  'science.org',
  'cell.com',
  'pnas.org',
  'nejm.org',
  'thelancet.com',
  'jamanetwork.com',
  'bmj.com',
  'pubmed.ncbi.nlm.nih.gov',
  'ncbi.nlm.nih.gov',
  'nih.gov',
  'who.int',
  'cdc.gov',
  'fda.gov',
  'arxiv.org',
  'biorxiv.org',
  'medrxiv.org'
];

const tier2Domains = [
  'quantamagazine.org',
  'scientificamerican.com',
  'technologyreview.com',
  'statnews.com',
  'spectrum.ieee.org',
  'sciencenews.org',
  'theconversation.com',
  'newscientist.com',
  'mit.edu',
  'stanford.edu',
  'harvard.edu',
  'ox.ac.uk',
  'cam.ac.uk',
  'mpg.de'
];

const tagScore = {
  primary_research: 5,
  review: 5,
  data: 4,
  methodology: 4,
  opposing_view: 4,
  expert_context: 3,
  ethics: 3,
  background: 2
};

const scored = deduped.map(source => {
  const url = source.url.toLowerCase();

  const domainScore =
    tier1Domains.some(d => url.includes(d)) ? 5 :
    tier2Domains.some(d => url.includes(d)) ? 3 :
    1;

  return {
    ...source,
    _score: domainScore + (tagScore[source.tag] || 1)
  };
});

scored.sort((a, b) => b._score - a._score);

const final = scored.slice(0, 6);

return final.map(source => ({
  json: {
    url: source.url,
    title: source.title,
    justification: source.justification,
    tag: source.tag
  }
}));

