const item = $input.first().json;
const content = item.content || '';
const sourceUrl = item.url || '';
const sourceTitle = item.title || '';
const sourceTag = item.tag || 'unknown';

if (!content || content.length < 200) {
  return [{
    json: {
      text: 'No content could be extracted.',
      metadata: { source_url: sourceUrl, source_title: sourceTitle, source_tag: sourceTag, chunk_index: 0 }
    }
  }];
}

const cleaned = content.replace(/\n{3,}/g, '\n\n').replace(/\s{2,}/g, ' ').trim();
const paragraphs = cleaned.split(/\n\n+/);
const chunks = [];
let currentChunk = '';
let chunkIndex = 0;

for (const para of paragraphs) {
  const combined = currentChunk + '\n\n' + para;
  if (combined.split(/\s+/).length > 600 && currentChunk.length > 0) {
    chunks.push({ text: currentChunk.trim(), chunk_index: chunkIndex });
    currentChunk = para;
    chunkIndex++;
  } else {
    currentChunk = combined;
  }
}

if (currentChunk.trim().length > 100) {
  chunks.push({ text: currentChunk.trim(), chunk_index: chunkIndex });
}

if (chunks.length === 0) {
  return [{
    json: {
      text: 'No content could be extracted.',
      metadata: { source_url: sourceUrl, source_title: sourceTitle, source_tag: sourceTag, chunk_index: 0 }
    }
  }];
}

return chunks.map(c => ({
  json: {
    text: c.text,
    metadata: { source_url: sourceUrl, source_title: sourceTitle, source_tag: sourceTag, chunk_index: c.chunk_index }
  }
}));

