const output = $input.first().json.output;
const brief = $('Compile Blog Brief').first().json;

return [{
  json: {
    STATUS: 'PENDING',
    DATE: new Date().toISOString().split('T')[0],
    VIDEO_ID: brief.videoId,
    VIDEO_URL: brief.videoUrl,
    KEYWORD: brief.keyword,
    CHANNEL: brief.channelName,
    TITLE: output.title,
    SUBTITLE: output.subtitle,
    META_DESCRIPTION: output.meta_description,
    BLOCKS_JSON: JSON.stringify(output.blocks),
    BLOCK_COUNT: output.blocks.length
  }
}];

const row = $input.first().json;
const blocks = JSON.parse(row.BLOCKS_JSON);

const imagePlaceholders = blocks
  .map((block, index) => ({ ...block, originalIndex: index }))
.filter(block => 
  block.type === 'image' && (
    !block.src ||
    String(block.src).toUpperCase().includes('PLACEHOLDER') ||
    !String(block.src).startsWith('http')
  )
);

return [{
  json: {
    ...row,
    blocks,
    imagePlaceholders,
    imageCount: imagePlaceholders.length
  }
}];

const data = $input.first().json;
const placeholders = data.imagePlaceholders;

if (placeholders.length === 0) {
  return [{
    json: {
      ...data,
      skipImageSearch: true
    }
  }];
}

return placeholders.map(img => ({
  json: {
    alt: img.alt,
    caption: img.caption || '',
    originalIndex: img.originalIndex,
    searchQuery: img.alt.substring(0, 100)
  }
}));

const data = $input.first().json;
const blocks = data.blocks || JSON.parse(data.BLOCKS_JSON || '[]');

const ghostBlocks = blocks.map(block => {
  switch (block.type) {
    case 'paragraph':
      return { type: 'paragraph', text: block.text };

    case 'heading':
      return { type: 'heading', text: block.text, level: block.level || 2 };

    case 'quote':
      return { type: 'quote', text: block.text };

    case 'image':
      return {
        type: 'image',
        src: block.src,
        alt: block.alt || '',
        caption: block.caption || ''
      };

    case 'divider':
      return { type: 'divider' };

    case 'callout':
      return {
        type: 'callout',
        text: (block.text || '')
          .replace(/\*\*(.+?)\*\*/g, '$1')
          .replace(/\*(.+?)\*/g, '$1')
          .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1'),
        emoji: block.emoji || '',
        color: block.color || 'grey'
      };

    case 'call_to_action':
      return {
        type: 'call_to_action',
        text: block.text,
        button_text: block.button_text || '',
        button_url: block.button_url || ''
      };

    case 'paywall':
      return { type: 'paywall' };

    case 'button':
      return {
        type: 'button',
        text: block.text,
        url: block.url,
        alignment: block.alignment || 'center'
      };

    case 'signup':
      return {
        type: 'signup',
        heading: block.heading,
        subheading: block.subheading,
        button_text: block.button_text,
        background_color: '#15171A',
        button_color: '#000000'
      };

    default:
      return { type: 'paragraph', text: block.text || '' };
  }
});

return [{
  json: {
    title: data.title || data.TITLE,
    subtitle: data.subtitle || data.SUBTITLE,
    meta_description: data.meta_description || data.META_DESCRIPTION,
    row_number: data.row_number,
    feature_image: data.feature_image || data.FEATURE_IMAGE || '',
    content: ghostBlocks
  }
}];

const items = $input.all();

return items.map((item, index) => {
  const results = item.json.results || [];

  const candidates = results
    .map((img, i) => {
