const items = $input.all();

function parseToMinutes(published) {
  if (!published) return null;

  const isoDate = new Date(published);
  if (!isNaN(isoDate.getTime())) {
    const diffMs = Date.now() - isoDate.getTime();
    return Math.max(0, diffMs / 60000);
  }

  let cleaned = String(published)
    .replace(/^(Premiered|Streamed)\s+/i, '')
    .replace(/^New\s*/i, '')
    .trim();

  const match = cleaned.match(/^(\d+)\s+(second|minute|hour|day|week|month|year)s?\s+ago$/i);

  if (match) {
    const value = parseInt(match[1], 10);
    const unit = match[2].toLowerCase();

    const multipliers = {
      second: 1 / 60,
      minute: 1,
      hour: 60,
      day: 1440,
      week: 10080,
      month: 43200,
      year: 525600
    };

    return value * (multipliers[unit] || null);
  }

  return null;
}

return items
  .filter(item => {
    return item.json && !item.json.error && item.json.video_id;
  })
  .map(item => {
    const publishedValue =
      item.json.published_date ||
      item.json.publishedDate ||
      item.json.date ||
      item.json.published_time ||
      item.json.publishedTime;

    const minutesAgo = parseToMinutes(publishedValue);

    return {
      json: {
        ...item.json,
        published_date: publishedValue,
        minutes_ago: minutesAgo === null ? null : Math.round(minutesAgo),
        pubdate_display: minutesAgo === null
          ? ''
          : `${Math.round(minutesAgo)} minutes ago`
      }
    };
  });

const inputItems = $input.all();

let records = [];

// Handle different possible Apify/n8n shapes
for (const item of inputItems) {
  const data = item.json;

  if (Array.isArray(data)) {
    records.push(...data);
  } else if (Array.isArray(data.items)) {
    records.push(...data.items);
  } else if (Array.isArray(data.results)) {
    records.push(...data.results);
  } else if (Array.isArray(data.data)) {
    records.push(...data.data);
  } else {
    records.push(data);
  }
}

// Keep only actual YouTube videos.
// This removes rows like:
// { error: "NO_VIDEOS", note: "No videos found on the page." }
const videos = records.filter(item => {
  return item &&
    item.type === 'video' &&
    item.id &&
    !item.error;
});

return videos.map((video, index) => ({
