    transcript: (video.subtitles || [])
      .map(sub => sub.plaintext)
      .filter(Boolean)
      .join('\n\n'),

    hashtags: video.hashtags || [],

    is_paid_content: video.isPaidContent ?? false,
    is_members_only: video.isMembersOnly ?? false,
    comments_turned_off: video.commentsTurnedOff ?? false
  }
}));

const items = $input.all();

function cleanText(value, maxChars = null) {
  const text = String(value || '')
    .replace(/\r?\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  return maxChars ? text.substring(0, maxChars) : text;
}

function wordCount(value) {
  const text = cleanText(value);
  if (!text) return 0;
  return text.split(/\s+/).length;
}

const candidates = items.map((item, index) => {
  const transcript = item.json.TRANSCRIPT || '';
  const description = item.json['VIDEO DESCRIPTION'] || '';
  const notes = item.json.NOTES || item.json.NOTE || '';

