const aiJson = $('AI Agent4').first().json;
const output = aiJson.output || aiJson;
const originalItems = $('Code in JavaScript10').first().json.original_items || [];
const assessments = output.assessments || [];

const selectedCount = assessments.filter(a => a.verdict === 'SELECTED').length;
const noAcceptable = output.selection_status === 'NO_ACCEPTABLE_CANDIDATE' || output.winner_index === 0;

return originalItems.map((item, index) => {
  const candidateIndex = index + 1;
  const assessment = assessments.find(a => Number(a.candidate_index) === candidateIndex);

  let verdict = assessment ? assessment.verdict : 'REJECTED';

  // Safety guard: if the model says no acceptable candidate, force all rows to REJECTED.
  if (noAcceptable) {
    verdict = 'REJECTED';
  }

  // Safety guard: if the model accidentally selects multiple candidates, only keep winner_index.
  if (!noAcceptable && selectedCount !== 1) {
    verdict = Number(output.winner_index) === candidateIndex ? 'SELECTED' : 'REJECTED';
  }

  const scienceScore = assessment?.science_relevance_score ?? '';
  const evidenceScore = assessment?.evidence_quality_score ?? '';
  const bullshitRisk = assessment?.bullshit_risk ?? '';
  const articleScore = assessment?.article_potential_score ?? '';
  const reasoning = assessment?.reasoning ?? 'No assessment returned. Defaulting to rejected.';

  const verdictReasoning =
    `Science ${scienceScore}/10 | Evidence ${evidenceScore}/10 | ` +
    `Article ${articleScore}/10 | Bullshit risk: ${bullshitRisk}. ` +
    reasoning;

  return {
    json: {
      ...item,
      verdict,
      verdict_reasoning: verdictReasoning,
      winner_reasoning: verdict === 'SELECTED' ? output.winner_reasoning : '',
      batch_rejection_summary: output.rejection_summary || ''
    }
  };
});
